class RabbitMQConnection:
    """Base class for RabbitMQ connections with reconnection logic."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        virtual_host: str = '/',
        heartbeat: int = 600,
        connection_attempts: int = 3,
        retry_delay: int = 5
    ):
        self.host = host
        self.port = port
        self.credentials = pika.PlainCredentials(username, password)
        self.virtual_host = virtual_host
        self.heartbeat = heartbeat
        self.connection_attempts = connection_attempts
        self.retry_delay = retry_delay
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.channel.Channel] = None

    def _get_connection_params(self) -> pika.ConnectionParameters:
        return pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            credentials=self.credentials,
            virtual_host=self.virtual_host,
            heartbeat=self.heartbeat,
            connection_attempts=self.connection_attempts,
            retry_delay=self.retry_delay,
            blocked_connection_timeout=300
        )

    def connect(self):
        """Establish connection to RabbitMQ."""
        try:
            params = self._get_connection_params()
            self.connection = pika.BlockingConnection(params)
            self.channel = self.connection.channel()
            logger.info(f"Connected to RabbitMQ at {self.host}:{self.port}")
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def close(self):
        """Close the connection."""
        try:
            if self.connection and not self.connection.is_closed:
                self.connection.close()
                logger.info("RabbitMQ connection closed")
        except Exception as e:
            logger.error(f"Error closing connection: {e}")

    def _ensure_connection(self):
        """Ensure the connection is active, reconnect if necessary."""
        if self.connection is None or self.connection.is_closed:
            logger.warning("Connection lost, reconnecting...")
            self.connect()

    def declare_exchange(self, exchange_name: str, exchange_type: str = 'direct', durable: bool = True):
        """Declare an exchange."""
        self._ensure_connection()
        self.channel.exchange_declare(
            exchange=exchange_name,
            exchange_type=exchange_type,
            durable=durable
        )
        logger.info(f"Exchange '{exchange_name}' declared (type={exchange_type}, durable={durable})")

    def declare_queue(
        self,
        queue_name: str,
        durable: bool = True,
        arguments: Optional[Dict] = None
    ) -> str:
        """Declare a queue and return its name."""
        self._ensure_connection()
        result = self.channel.queue_declare(
            queue=queue_name,
            durable=durable,
            arguments=arguments or {}
        )
        logger.info(f"Queue '{queue_name}' declared (durable={durable})")
        return result.method.queue

    def bind_queue(self, queue_name: str, exchange_name: str, routing_key: str):
        """Bind a queue to an exchange."""
        self._ensure_connection()
        self.channel.queue_bind(
            queue=queue_name,
            exchange=exchange_name,
            routing_key=routing_key
        )
        logger.info(f"Queue '{queue_name}' bound to exchange '{exchange_name}' with key '{routing_key}'")


class TaskPublisher(RabbitMQConnection):
    """Publisher for sending task messages to RabbitMQ."""

    EXCHANGE_NAME = 'task_exchange'
    TASK_QUEUE = 'task_queue'
    DLX_EXCHANGE = 'task_dlx_exchange'
    DLX_QUEUE = 'task_dlx_queue'
    RESULT_QUEUE = 'task_result_queue'

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._setup_done = False

    def setup(self):
        """Set up exchanges, queues, and bindings."""
        self.connect()

        # Enable publisher confirms
        self.channel.confirm_delivery()

        # Declare main exchange
        self.declare_exchange(self.EXCHANGE_NAME, exchange_type='direct')

        # Declare dead-letter exchange and queue
        self.declare_exchange(self.DLX_EXCHANGE, exchange_type='direct')
        self.declare_queue(self.DLX_QUEUE, durable=True)
        self.bind_queue(self.DLX_QUEUE, self.DLX_EXCHANGE, routing_key='dead_letter')

        # Declare main task queue with DLX support and priority
        queue_args = {
            'x-dead-letter-exchange': self.DLX_EXCHANGE,
            'x-dead-letter-routing-key': 'dead_letter',
            'x-max-priority': 10,
            'x-message-ttl': 86400000,  # 24 hours
            'x-queue-type': 'classic'
        }
        self.declare_queue(self.TASK_QUEUE, durable=True, arguments=queue_args)
        self.bind_queue(self.TASK_QUEUE, self.EXCHANGE_NAME, routing_key='task')

        # Declare result queue
        self.declare_queue(self.RESULT_QUEUE, durable=True)
        self.bind_queue(self.RESULT_QUEUE, self.EXCHANGE_NAME, routing_key='result')

        self._setup_done = True
        logger.info("Publisher setup complete")

    def publish_task(
        self,
        task_type: str,
        payload: Dict[str, Any],
        priority: int = TaskPriority.NORMAL,
        max_retries: int = 3
    ) -> str:
        """Publish a task message to the task queue."""
        if not self._setup_done:
            self.setup()

        self._ensure_connection()

        task = TaskMessage(
            task_type=task_type,
            payload=payload,
            priority=priority,
            max_retries=max_retries
        )

        properties = pika.BasicProperties(
            delivery_mode=2,  # persistent
            content_type='application/json',
            priority=priority,
            message_id=task.task_id,
            timestamp=int(time.time()),
            headers={
                'task_type': task_type,
                'retry_count': 0
            }
        )

        try:
            self.channel.basic_publish(
                exchange=self.EXCHANGE_NAME,
                routing_key='task',
                body=task.to_json(),
                properties=properties,
                mandatory=True
            )
            logger.info(f"Published task {task.task_id} (type={task_type}, priority={priority})")
            return task.task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message {task.task_id} was unroutable")
            raise
        except pika.exceptions.NackError:
            logger.error(f"Message {task.task_id} was nacked by broker")
            raise

    def publish_batch(self, tasks: list) -> list:
        """Publish multiple tasks. Each item is a dict with task_type, payload, and optional priority."""
        task_ids = []
        for task_data in tasks:
            task_id = self.publish_task(
                task_type=task_data['task_type'],
                payload=task_data['payload'],
                priority=task_data.get('priority', TaskPriority.NORMAL),
                max_retries=task_data.get('max_retries', 3)
            )
            task_ids.append(task_id)
        return task_ids

    def publish_result(self, task_id: str, result: Dict[str, Any], status: str = TaskStatus.COMPLETED):
        """Publish a task result."""
        self._ensure_connection()

        result_message = {
            'task_id': task_id,
            'status': status,
            'result': result,
            'completed_at': datetime.utcnow().isoformat()
        }

        properties = pika.BasicProperties(
            delivery_mode=2,
            content_type='application/json',
            correlation_id=task_id
        )

        self.channel.basic_publish(
            exchange=self.EXCHANGE_NAME,
            routing_key='result',
            body=json.dumps(result_message),
            properties=properties
        )
        logger.info(f"Published result for task {task_id} (status={status})")


class TaskConsumer(RabbitMQConnection):
    """Consumer for processing task messages from RabbitMQ."""

    EXCHANGE_NAME = 'task_exchange'
    TASK_QUEUE = 'task_queue'
    DLX_EXCHANGE = 'task_dlx_exchange'
    DLX_QUEUE = 'task_dlx_queue'

    def __init__(self, prefetch_count: int = 1, **kwargs):
        super().__init__(**kwargs)
        self.prefetch_count = prefetch_count
        self._task_handlers: Dict[str, Callable] = {}
        self._running = False
        self._result_publisher: Optional[TaskPublisher] = None

    def register_handler(self, task_type: str, handler: Callable):
        """Register a handler function for a specific task type."""
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def setup(self):
        """Set up the consumer."""
        self.connect()
        self.channel.basic_qos(prefetch_count=self.prefetch_count)

        # Set up result publisher for sending results back
        self._result_publisher = TaskPublisher(
            host=self.host,
            port=self.port
        )
        self._result_publisher.setup()

        logger.info("Consumer setup complete")

    def _on_message(self, channel, method, properties, body):
        """Callback for processing received messages."""
        task = None
        try:
            task = TaskMessage.from_json(body.decode('utf-8'))
            logger.info(f"Received task {task.task_id} (type={task.task_type}, retry={task.retry_count})")

            handler = self._task_handlers.get(task.task_type)
            if handler is None:
                logger.warning(f"No handler registered for task type: {task.task_type}")
                # Reject and don't requeue - send to DLX
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Process the task
            task.status = TaskStatus.PROCESSING
            result = handler(task)

            # Acknowledge successful processing
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info(f"Task {task.task_id} completed successfully")

            # Publish result
            if self._result_publisher:
                self._result_publisher.publish_result(
                    task_id=task.task_id,
                    result=result if isinstance(result, dict) else {'result': result},
                    status=TaskStatus.COMPLETED
                )

        except Exception as e:
            logger.error(f"Error processing task: {e}", exc_info=True)
            self._handle_failure(channel, method, properties, body, task, e)

    def _handle_failure(self, channel, method, properties, body, task, error):
        """Handle task processing failure with retry logic."""
        if task and task.retry_count < task.max_retries:
            # Retry: republish with incremented retry count
            task.retry_count += 1
            task.status = TaskStatus.RETRYING

            retry_properties = pika.BasicProperties(
                delivery_mode=2,
                content_type='application/json',
                priority=properties.priority if properties.priority else TaskPriority.NORMAL,
                message_id=task.task_id,
                headers={
                    'task_type': task.task_type,
                    'retry_count': task.retry_count,
                    'error': str(error)
                }
            )

            # Acknowledge the original message
            channel.basic_ack(delivery_tag=method.delivery_tag)

            # Republish with delay (exponential backoff simulation)
            time.sleep(min(2 ** task.retry_count, 30))
            channel.basic_publish(
                exchange=self.EXCHANGE_NAME,
                routing_key='task',
                body=task.to_json(),
                properties=retry_properties
            )
            logger.info(f"Task {task.task_id} scheduled for retry ({task.retry_count}/{task.max_retries})")
        else:
            # Max retries exceeded, send to DLX
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
            task_id = task.task_id if task else 'unknown'
            logger.error(f"Task {task_id} failed permanently after max retries")

            if self._result_publisher and task:
                self._result_publisher.publish_result(
                    task_id=task.task_id,
                    result={'error': str(error)},
                    status=TaskStatus.FAILED
                )

    def start_consuming(self):
        """Start consuming messages from the task queue."""
        if not self.channel:
            self.setup()

        self._running = True
        self.channel.basic_consume(
            queue=self.TASK_QUEUE,
            on_message_callback=self._on_message,
            auto_ack=False
        )

        logger.info(f"Consumer started. Waiting for tasks on '{self.TASK_QUEUE}'...")
        logger.info(f"Registered handlers: {list(self._task_handlers.keys())}")

        try:
            while self._running:
                self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self.stop_consuming()
        except pika.exceptions.ConnectionClosedByBroker:
            logger.error("Connection closed by broker, attempting to reconnect...")
            self._reconnect_and_consume()
        except pika.exceptions.AMQPConnectionError:
            logger.error("Connection error, attempting to reconnect...")
            self._reconnect_and_consume()

    def _reconnect_and_consume(self):
        """Reconnect and resume consuming."""
        retries = 0
        while self._running and retries < 10:
            try:
                time.sleep(min(2 ** retries, 60))
                self.setup()
                self.start_consuming()
                return
            except Exception as e:
                retries += 1
                logger.error(f"Reconnect attempt {retries} failed: {e}")

        logger.error("Max reconnection attempts reached. Shutting down.")

    def stop_consuming(self):
        """Stop consuming messages."""
        self._running = False
        if self.channel and self.channel.is_open:
            self.channel.stop_consuming()
        self.close()
        if self._result_publisher:
            self._result_publisher.close()
        logger.info("Consumer stopped")


class DeadLetterConsumer(RabbitMQConnection):
    """Consumer for processing dead-letter messages."""

    DLX_QUEUE = 'task_dlx_queue'

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._handler: Optional[Callable] = None

    def set_handler(self, handler: Callable):
        """Set handler for dead letter messages."""
        self._handler = handler

    def setup(self):
        self.connect()
        self.channel.basic_qos(prefetch_count=1)

    def _on_dead_letter(self, channel, method, properties, body):
        """Process dead letter messages."""
        try:
            message = json.loads(body.decode('utf-8'))
            logger.warning(f"Dead letter received: {message.get('task_id', 'unknown')}")

            if self._handler:
                self._handler(message, properties)

            channel.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            logger.error(f"Error processing dead letter: {e}")
            channel.basic_ack(delivery_tag=method.delivery_tag)

    def start_consuming(self):
        self.setup()
        self.channel.basic_consume(
            queue=self.DLX_QUEUE,
            on_message_callback=self._on_dead_letter,
            auto_ack=False
        )
        logger.info("Dead letter consumer started")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            self.channel.stop_consuming()
            self.close()


