def run_publisher_demo():
    """Demonstrate the publisher functionality."""
    publisher = TaskPublisher(host='localhost', port=5672)
    try:
        publisher.setup()

        # Publish individual tasks
        task_id = publisher.publish_task(
            task_type='send_email',
            payload={
                'recipient': 'user@example.com',
                'subject': 'Welcome!',
                'body': 'Welcome to our platform.'
            },
            priority=TaskPriority.HIGH
        )
        print(f"Published email task: {task_id}")

        task_id = publisher.publish_task(
            task_type='process_data',
            payload={
                'source': 'database',
                'operation': 'aggregate',
                'record_count': 5000
            },
            priority=TaskPriority.NORMAL
        )
        print(f"Published data processing task: {task_id}")

        task_id = publisher.publish_task(
            task_type='send_notification',
            payload={
                'channel': 'push',
                'user_id': 'user_123',
                'message': 'Your order has been shipped!'
            },
            priority=TaskPriority.LOW
        )
        print(f"Published notification task: {task_id}")

        # Publish batch of tasks
        batch_tasks = [
            {
                'task_type': 'generate_report',
                'payload': {'report_type': 'monthly_sales', 'date_range': 'last_30_days'},
                'priority': TaskPriority.CRITICAL
            },
            {
                'task_type': 'send_email',
                'payload': {'recipient': 'admin@example.com', 'subject': 'System Alert', 'body': 'Check logs'},
                'priority': TaskPriority.HIGH
            },
            {
                'task_type': 'process_data',
                'payload': {'source': 'api', 'operation': 'transform', 'record_count': 1000},
                'priority': TaskPriority.NORMAL
            },
        ]
        task_ids = publisher.publish_batch(batch_tasks)
        print(f"Published batch of {len(task_ids)} tasks: {task_ids}")

    finally:
        publisher.close()


def run_consumer():
    """Run the task consumer."""
    consumer = TaskConsumer(host='localhost', port=5672, prefetch_count=2)

    # Register task handlers
    consumer.register_handler('send_email', handle_email_task)
    consumer.register_handler('process_data', handle_data_processing_task)
    consumer.register_handler('send_notification', handle_notification_task)
    consumer.register_handler('generate_report', handle_report_generation_task)

    try:
        consumer.setup()
        consumer.start_consuming()
    except KeyboardInterrupt:
        consumer.stop_consuming()
    finally:
        consumer.close()


